select books.book_id , title , author , genre , pages , rating_spread , polarization_score from(select book_id , highest_rating , lowest_rating , rating_spread , ROUND((polarized_count::numeric / total_session ) ,2) as polarization_score from  (select book_id , max(highest_rating) as highest_rating , max(lowest_rating) as lowest_rating , max(rating_spread) as rating_spread , max(total_session) as total_session , count(*) as polarized_count from(select one.book_id , highest_rating , lowest_rating , rating_spread , session_rating , total_session  from (select one_rating.book_id , max(session_rating) as highest_rating , min(session_rating) as lowest_rating, (max(session_rating) - min(session_rating)) as rating_spread , count(session_id) as total_session from (select book_id  from (select book_id , session_rating from (select unique_books.book_id , session_rating from (select book_id from reading_sessions group by book_id having count(session_id) >=5 ) as unique_books join reading_sessions on unique_books.book_id = reading_sessions.book_id) as ids_rating ) as grouping_rating group by book_id having
(bool_or(session_rating = 4) AND bool_or(session_rating = 1))
   OR (bool_or(session_rating = 4) AND bool_or(session_rating = 2))
   OR (bool_or(session_rating = 5) AND bool_or(session_rating = 1))
   OR (bool_or(session_rating = 5) AND bool_or(session_rating = 2)) ) as one_rating join reading_sessions on one_rating.book_id = reading_sessions.book_id group by one_rating.book_id ) as one join reading_sessions on one.book_id = reading_sessions.book_id  where session_rating >= 4 or session_rating <=2 ) as two group by book_id ) as three )as res join books on res.book_id = books.book_id where polarization_score >= .6 order by polarization_score desc , title desc;
